// ============================================================
// 2) REPLACE handleMessageReaction (private async method, currently
//    ~line 11289-11339) with this version. It adds real-vote recording
//    as a new, independent, best-effort step that runs BEFORE the
//    existing "reaction abuse" bookkeeping, so a /duelo_debate message
//    that falls outside the "message" activity-log window still gets
//    its votes counted (the existing code below returns early when the
//    original author can't be resolved — that early return must not
//    also swallow vote recording).
// ============================================================
  /**
   * Records native message reactions (Telegram `message_reaction`) into the
   * activity log as kind "reaction", keyed to the reacted-to message's author
   * (looked up by message id). Feeds the /reaccion_abuso report; recording
   * only, never replies. Best-effort: an original outside the log window is
   * skipped, so it cannot attribute the reaction and does nothing.
   *
   * Also feeds real votes for /duelo_debate: every reactor casts one vote on
   * the reacted message via PrismaDebateDuelVoteRepository (kind
   * "debate_vote" in the same activity log, no new table). That step is
   * independent of the reaction-abuse bookkeeping below, so it still runs
   * even when the reacted message's author can't be resolved.
   */
  private async handleMessageReaction(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
  ): Promise<BotReply | null> {
    const reaction = update.reaction;
    if (
      update.kind !== "message_reaction" ||
      !context.chatId ||
      reaction === undefined ||
      reaction.messageId === undefined ||
      reaction.emojisAdded.length === 0
    ) {
      return null;
    }

    if (reaction.userId !== undefined) {
      try {
        await new PrismaDebateDuelVoteRepository(
          this.chatActivityRepository,
        ).recordVote(
          context.tenantId,
          context.chatId,
          BigInt(reaction.messageId),
          reaction.userId,
        );
      } catch {
        // Non-fatal: vote tracking is best-effort.
      }
    }

    const original = await this.chatActivityRepository.findOriginalMessage(
      context.tenantId,
      context.chatId,
      BigInt(reaction.messageId),
    );
    if (!original || original.telegramUserId === undefined) {
      return null;
    }

    const authorId = original.telegramUserId;
    const authorUsername = original.username;
    try {
      for (const emoji of reaction.emojisAdded) {
        await this.chatActivityRepository.record({
          tenantId: context.tenantId,
          chatId: context.chatId,
          kind: "reaction",
          telegramUserId: authorId,
          ...(authorUsername !== undefined ? { username: authorUsername } : {}),
          text: emoji,
          messageId: BigInt(reaction.messageId),
        });
      }
    } catch {
      // Non-fatal: the activity log is best-effort.
    }

    return null;
  }

// ============================================================
